import pytest

from mymodule import run_length_encode  # Adjust import as needed


class TestRunLengthEncodeHappyPath:
    """Tests for typical, expected inputs."""

    def test_simple_repeating_characters(self):
        assert run_length_encode("aaabbc") == [("a", 3), ("b", 2), ("c", 1)]

    def test_all_same_character(self):
        assert run_length_encode("aaaaa") == [("a", 5)]

    def test_no_repeats(self):
        assert run_length_encode("abcdef") == [
            ("a", 1),
            ("b", 1),
            ("c", 1),
            ("d", 1),
            ("e", 1),
            ("f", 1),
        ]

    def test_alternating_characters(self):
        assert run_length_encode("ababab") == [
            ("a", 1),
            ("b", 1),
            ("a", 1),
            ("b", 1),
            ("a", 1),
            ("b", 1),
        ]

    def test_mixed_runs(self):
        assert run_length_encode("aabbbaaac") == [
            ("a", 2),
            ("b", 3),
            ("a", 3),
            ("c", 1),
        ]

    def test_long_run(self):
        s = "x" * 1000
        assert run_length_encode(s) == [("x", 1000)]


class TestRunLengthEncodeEdgeCases:
    """Tests for boundary conditions."""

    def test_empty_string(self):
        assert run_length_encode("") == []

    def test_single_character(self):
        assert run_length_encode("a") == [("a", 1)]

    def test_two_same_characters(self):
        assert run_length_encode("aa") == [("a", 2)]

    def test_two_different_characters(self):
        assert run_length_encode("ab") == [("a", 1), ("b", 1)]

    def test_whitespace_characters(self):
        assert run_length_encode("   ") == [(" ", 3)]

    def test_mixed_whitespace_and_letters(self):
        assert run_length_encode("aa  bb") == [("a", 2), (" ", 2), ("b", 2)]

    def test_special_characters(self):
        assert run_length_encode("!!@@##") == [("!", 2), ("@", 2), ("#", 2)]

    def test_digits(self):
        assert run_length_encode("11122") == [("1", 3), ("2", 2)]

    def test_case_sensitivity(self):
        # Uppercase and lowercase should be treated as distinct.
        assert run_length_encode("aAaA") == [
            ("a", 1),
            ("A", 1),
            ("a", 1),
            ("A", 1),
        ]

    def test_unicode_characters(self):
        assert run_length_encode("ééé😀😀") == [("é", 3), ("😀", 2)]

    def test_newlines_and_tabs(self):
        assert run_length_encode("\n\n\t\t") == [("\n", 2), ("\t", 2)]

    def test_returns_list_type(self):
        result = run_length_encode("aaa")
        assert isinstance(result, list)

    def test_returns_tuples(self):
        result = run_length_encode("aabb")
        for item in result:
            assert isinstance(item, tuple)
            assert len(item) == 2

    def test_empty_returns_list(self):
        result = run_length_encode("")
        assert isinstance(result, list)
        assert result == []


class TestRunLengthEncodeErrorCases:
    """Tests for invalid inputs which should raise errors."""

    def test_none_raises(self):
        with pytest.raises(TypeError):
            run_length_encode(None)

    def test_integer_raises(self):
        with pytest.raises(TypeError):
            run_length_encode(12345)

    def test_list_raises(self):
        # Lists are iterable, so the function will not raise but return tuples
        # of list elements. We expect TypeError because `if not s` works but
        # indexing/comparing should still happen. Actually a list would work...
        # so we use a non-iterable to ensure TypeError.
        with pytest.raises(TypeError):
            run_length_encode(123.45)

    def test_dict_raises(self):
        with pytest.raises(TypeError):
            run_length_encode({"a": 1})


class TestRunLengthEncodeReconstruction:
    """Property-style tests: encoding then decoding should yield original."""

    @pytest.mark.parametrize(
        "s",
        [
            "",
            "a",
            "aa",
            "ab",
            "aaabbc",
            "Hello, World!",
            "112233",
            "    ",
            "aAaAaA",
        ],
    )
    def test_roundtrip(self, s):
        encoded = run_length_encode(s)
        decoded = "".join(ch * count for ch, count in encoded)
        assert decoded == s

    @pytest.mark.parametrize(
        "s",
        [
            "aaabbc",
            "abc",
            "aaaa",
            "xy",
        ],
    )
    def test_total_count_matches_length(self, s):
        encoded = run_length_encode(s)
        assert sum(count for _, count in encoded) == len(s)
